import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../data/api';

const s = {
  page: { padding: '2rem', maxWidth: '700px', margin: '0 auto' },
  back: { color: '#7c6af7', cursor: 'pointer', marginBottom: '1.5rem', fontSize: '0.85rem', background: 'none', border: 'none' },
  title: { fontSize: '1.5rem', fontWeight: 700, color: '#fff', marginBottom: '0.3rem' },
  sub: { color: '#888', marginBottom: '2rem' },
  card: { background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '12px', padding: '1.5rem', marginBottom: '1.5rem' },
  qNum: { color: '#7c6af7', fontSize: '0.85rem', fontWeight: 600, marginBottom: '0.5rem' },
  question: { color: '#fff', fontSize: '1rem', marginBottom: '1rem', lineHeight: 1.5 },
  option: { display: 'block', width: '100%', padding: '0.7rem 1rem', marginBottom: '0.5rem', background: '#0f0f1a', border: '1px solid #2a2a4a', borderRadius: '8px', color: '#ccc', cursor: 'pointer', textAlign: 'left', fontSize: '0.9rem' },
  btn: { padding: '0.7rem 2rem', background: '#7c6af7', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 600, fontSize: '1rem' },
  result: { background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '12px', padding: '2rem', textAlign: 'center' },
  score: { fontSize: '3rem', fontWeight: 700, color: '#7c6af7', marginBottom: '0.5rem' },
  resultItem: { background: '#0f0f1a', borderRadius: '8px', padding: '1rem', marginBottom: '0.75rem', textAlign: 'left' },
};

export default function QuizPage() {
  const { courseId, level } = useParams();
  const navigate = useNavigate();
  const [quiz, setQuiz] = useState([]);
  const [answers, setAnswers] = useState({});
  const [result, setResult] = useState(null);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    api.get(`/quiz/${courseId}/${level}`).then(r => setQuiz(r.data));
  }, [courseId, level]);

  const select = (qi, oi) => {
    if (!submitted) setAnswers(prev => ({ ...prev, [qi]: oi }));
  };

  const submit = async () => {
    if (Object.keys(answers).length < quiz.length) return alert('Please answer all questions');
    const answersArr = quiz.map((_, i) => answers[i]);
    const res = await api.post('/quiz/submit', { courseId, level, answers: answersArr });
    setResult(res.data);
    setSubmitted(true);
    await api.post('/progress/quiz', { courseId, topicId: level, score: res.data.score, total: res.data.total, level });
  };

  const optionStyle = (qi, oi) => {
    let style = { ...s.option };
    if (submitted && result) {
      if (oi === result.results[qi]?.correctIndex) style = { ...style, borderColor: '#4caf50', color: '#4caf50' };
      else if (answers[qi] === oi && oi !== result.results[qi]?.correctIndex) style = { ...style, borderColor: '#f44336', color: '#f44336' };
    } else if (answers[qi] === oi) {
      style = { ...style, borderColor: '#7c6af7', color: '#7c6af7' };
    }
    return style;
  };

  if (!quiz.length) return <div style={{ color: '#fff', padding: '2rem' }}>Loading quiz...</div>;

  return (
    <div style={s.page}>
      <button style={s.back} onClick={() => navigate(`/course/${courseId}`)}>← Back to Course</button>
      <div style={s.title}>{level.charAt(0).toUpperCase() + level.slice(1)} Quiz</div>
      <div style={s.sub}>{quiz.length} questions</div>

      {quiz.map((q, qi) => (
        <div key={q._id} style={s.card}>
          <div style={s.qNum}>Question {qi + 1}</div>
          <div style={s.question}>{q.question}</div>
          {q.options.map((opt, oi) => (
            <button key={oi} style={optionStyle(qi, oi)} onClick={() => select(qi, oi)}>{opt}</button>
          ))}
          {submitted && result?.results[qi]?.explanation && (
            <div style={{ color: '#888', fontSize: '0.85rem', marginTop: '0.5rem' }}>
              💡 {result.results[qi].explanation}
            </div>
          )}
        </div>
      ))}

      {!submitted ? (
        <button style={s.btn} onClick={submit}>Submit Quiz</button>
      ) : (
        <div style={s.result}>
          <div style={s.score}>{result.percentage}%</div>
          <div style={{ color: '#ccc' }}>{result.score} / {result.total} correct</div>
          <div style={{ marginTop: '1rem', color: result.percentage >= 70 ? '#4caf50' : '#ff9800' }}>
            {result.percentage >= 70 ? '🎉 Great job!' : '📚 Keep practicing!'}
          </div>
          <button style={{ ...s.btn, marginTop: '1.5rem' }} onClick={() => navigate(`/course/${courseId}`)}>
            Back to Course
          </button>
        </div>
      )}
    </div>
  );
}
